[asy]
fill(Circle((-1,0),5),gray(0.7));
fill(Circle((-3,0),3),white);
fill(circle((2,0),2),white);
dot((-3,0));
dot((2,0));
draw(Circle((-1,0),5));
draw((-3,0)--(0,0));
draw((2,0)--(4,0));
label("3",(-1.5,0),N);
label("2",(3,0),N);
draw(Circle((-3,0),3));
draw(Circle((2,0),2));
[/asy]

